-- ═══ RAILCARD (variant-specific) ═══
-- Partner offers: one row per variant
select 'railcard-' || lower(replace(replace(t.tier,' & ','-'),' ','-')) || '-partner-offers','Railcard','Railcard',t.tier,'perk','Partner offers and rewards','Partner offers and rewards','Exclusive deals from Railcard partners, such as Gousto, Craft Gin Club and Readly, alongside your travel savings.','Shopping','NONE',t.price,'Usage: Offers change regularly; see your Railcard''s offers section.','https://www.railcard.co.uk/','2026-07-08'
from (values ('16-25',2.92),('26-30',2.92),('Senior',2.92),('Two Together',2.92),('Family & Friends',2.92),('Network',2.92),('Disabled Persons',2.0)) as t(tier,price);
-- OPTIONAL (eligibility rule, not a benefit) — uncomment to include:
-- insert into perks (...) values ('railcard-16-25-mature-student-route', ... );

-- ═══ NATIONAL TRUST ═══
select 'national-trust-' || lower(t.tier) || '-' || r.slug,'National Trust','National Trust Membership',t.tier,r.feature,r.title,r.title,r.description,r.category,r.reset_period,t.price,r.usage_notes,r.source_url,'2026-07-08'
from (values ('Individual',6.0),('Joint',11.6),('Family',14.7),('Life',202.5)) as t(tier,price)
cross join (values
 ('free-entry-to-trusts-overseas','perk','Free entry to trusts overseas','Free visiting arrangements with INTO partner heritage organisations abroad, from the National Trust for Scotland to the Bahamas National Trust.','Travel','NONE','Usage: Show a valid membership card; some sites offer discounted rather than free entry.','https://www.nationaltrust.org.uk/membership/international-national-trusts-organisation'),
 ('vote-at-the-agm','feature','Vote at the AGM','Vote on resolutions at the Annual General Meeting and help shape the direction of the National Trust.','Lifestyle','ANNUALLY','Usage: Details arrive in the digital AGM booklet each autumn.','https://www.nationaltrust.org.uk/membership/what-to-enjoy-as-a-member'),
 ('member-exclusive-competitions','competition','Member-exclusive competitions','Exclusive competitions, partner discounts and promotions through member emails.','Competition','NONE','Usage: Opt in to member emails through My Account.','https://www.nationaltrust.org.uk/membership/what-to-enjoy-as-a-member'),
 ('online-members-area','feature','Online members'' area','Access the online members'' area, home to content made exclusively for members.','Entertainment','NONE','Usage: Sign in through My Account.','https://www.nationaltrust.org.uk/membership/what-to-enjoy-as-a-member')
) as r(slug,feature,title,description,category,reset_period,usage_notes,source_url);
select 'national-trust-' || lower(t.tier) || '-new-member-guest-pass','National Trust','National Trust Membership',t.tier,'perk','New member guest pass','New member guest pass','Bring a friend or family member for free with a single-use guest pass when you join by annual Direct Debit online.','Family','NONE',t.price,'Usage: Single use, participating places only, excludes bank holiday weekends.','https://www.nationaltrust.org.uk/membership/enquiries/new-member-guest-pass-terms-and-conditions','2026-07-08'
from (values ('Individual',6.0),('Joint',11.6),('Family',14.7)) as t(tier,price);

