-- ═══════════════ CORRECTIONS (FIX items) ═══════════════

-- Santander: overseas spending belongs at Edge (Edge Up inherits)
update perks set tier='Edge', price=3.0 where provider='Santander' and tier='Edge Up' and title='Fee-free overseas spending';
update perks set description='1% cashback on council tax, energy, water and communications Direct Debits, capped at £10 a month on Edge and £15 on Edge Up. Requires monthly pay-in and two Direct Debits.' where provider='Santander' and title='Cashback on household bills';

-- Nationwide: Fairer Share conditionality
update perks set description='Nationwide has paid an annual Fairer Share payment for four years running (£100 in June 2026). Requires a qualifying current account plus savings or a mortgage; paid at Nationwide''s discretion and not guaranteed.' where perk_id='nationwide-flexaccount-fairer-share-payment';

-- British Airways: retier and rename
delete from perks where provider='British Airways' and tier='Gold' and title='Priority boarding and baggage';
update perks set title='Priority baggage handling', titlegroup='Priority baggage handling', description='Your checked baggage is tagged priority and unloaded first as a Silver or Gold member.' where provider='British Airways' and tier='Silver' and title='Priority boarding and baggage';
update perks set title='Member-only offers', titlegroup='Member-only offers', description='Member-only offers including Avios seat sale promotions.' where provider='British Airways' and tier='Blue' and title='Avios seat sales';

-- Railcard: prices and conditions
update perks set price=2.5 where provider='Railcard' and tier in ('Two Together','Family & Friends','Network');
update perks set price=1.67 where provider='Railcard' and tier='Disabled Persons';
update perks set usage_notes='Usage: Both named cardholders must travel together; after 09:30 Mon-Fri, anytime weekends and public holidays.' where provider='Railcard' and tier='Two Together' and title='One third off rail fares';
update perks set usage_notes='Usage: London and South East area only; minimum fare applies Monday to Friday.' where provider='Railcard' and tier='Network' and title='One third off rail fares';

-- National Trust: parking wording
update perks set description='Free parking at many National Trust coast and countryside car parks.' where provider='National Trust' and title='Free parking';

-- Tesco: Clubcard Plus caveats
update perks set usage_notes='Usage: In-store only; discount capped at £20 per shop and £40 in any month.' where provider='Tesco' and title='10% off two big shops a month';
update perks set description='10% off selected Tesco own brands in-store, including F&F, Tesco Pet, Fred & Flo, Go Cook and Fox & Ivy.', usage_notes='Usage: In-store only, scan the Clubcard in the Tesco app.' where provider='Tesco' and title='10% off selected Tesco brands';

-- IKEA: hot drink conditions
update perks set description='Free tea or filter coffee in the in-store restaurant, Monday to Friday.', usage_notes='Usage: Mon-Fri only; excludes some smaller-format stores.' where provider='IKEA' and title='Free hot drink';

-- Costco: title already reads 'Optical, tyres and travel services' in the live table — no change needed.

-- ASOS: caveats
update perks set usage_notes='Usage: £15 minimum spend and checkout cut-off apply; excludes Channel Islands and some postcodes.' where provider='ASOS' and title='Unlimited next-day delivery';
update perks set description='Standard delivery, free only above a minimum spend threshold; otherwise charged.' where provider='ASOS' and tier='Free' and title='Standard delivery';

-- Blue Light Card: Deliveroo detail
update perks set description='12 months of free Deliveroo Plus Silver: free delivery on restaurant orders over £15 and grocery orders over £25.', usage_notes='Usage: 1 activation for 12 months, claimed via a unique code.' where provider='Blue Light Card' and title='Free Deliveroo Plus Silver';

-- Deliveroo: thresholds (price stays £7.99 per Ollie's decision)
update perks set description='Free delivery on restaurant orders over £10 and shop orders over £15.' where perk_id='deliveroo-plus-gold-free-delivery-over-10';
update perks set description='Free delivery on restaurant orders over £15 and shop orders over £25. Silver is now available through partners only, not sold directly.', usage_notes='Usage: Ongoing. Partner-only since 2026.' where perk_id='deliveroo-plus-silver-free-delivery-over-15';

-- Amazon: tier rename (also update user_memberships if anyone holds it)
